const express = require('express');
const http = require('http');
const socketIo = require('socket.io');
const crypto = require('crypto');
const bcrypt = require('bcrypt');
const rateLimit = require('express-rate-limit');

const app = express();
const server = http.createServer(app);
const io = socketIo(server, {
  cors: {
    origin: process.env.ALLOWED_ORIGINS?.split(',') || ['http://localhost:3000'],
    methods: ['GET', 'POST'],
    credentials: true
  }
});

app.use(express.json());

const loginLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 5,
  message: 'Too many login attempts'
});

const users = new Map();
const activeSessions = new Map();
const playerScores = new Map();
const gameState = new Map();

const SESSION_TIMEOUT = 30 * 60 * 1000;
const MAX_USERNAME_LENGTH = 20;
const MIN_USERNAME_LENGTH = 3;
const MAX_SCORE = 1000000;
const MIN_SCORE = 0;
const SALT_ROUNDS = 12;

function generateSecureToken() {
  return crypto.randomBytes(32).toString('hex');
}

function validateUsername(username) {
  if (typeof username !== 'string') return false;
  if (username.length < MIN_USERNAME_LENGTH || username.length > MAX_USERNAME_LENGTH) return false;
  return /^[a-zA-Z0-9_-]+$/.test(username);
}

function validateScore(score) {
  if (typeof score !== 'number') return false;
  if (!Number.isFinite(score)) return false;
  if (score < MIN_SCORE || score > MAX_SCORE) return false;
  return Number.isInteger(score);
}

function sanitizeInput(input) {
  if (typeof input !== 'string') return '';
  return input.trim().substring(0, MAX_USERNAME_LENGTH);
}

async function hashPassword(password) {
  return await bcrypt.hash(password, SALT_ROUNDS);
}

async function verifyPassword(password, hash) {
  return await bcrypt.compare(password, hash);
}

function createSession(userId, username) {
  const sessionToken = generateSecureToken();
  const sessionData = {
    userId,
    username,
    createdAt: Date.now(),
    lastActivity: Date.now(),
    authenticated: true
  };
  
  activeSessions.set(sessionToken, sessionData);
  
  setTimeout(() => {
    if (activeSessions.has(sessionToken)) {
      activeSessions.delete(sessionToken);
    }
  }, SESSION_TIMEOUT);
  
  return sessionToken;
}

function validateSession(sessionToken) {
  if (!sessionToken || typeof sessionToken !== 'string') return null;
  
  const session = activeSessions.get(sessionToken);
  if (!session) return null;
  
  if (Date.now() - session.lastActivity > SESSION_TIMEOUT) {
    activeSessions.delete(sessionToken);
    return null;
  }
  
  session.lastActivity = Date.now();
  return session;
}

function verifyScoreIntegrity(userId, newScore, previousScore) {
  const maxScoreIncrease = 1000;
  
  if (previousScore !== undefined) {
    const scoreDiff = newScore - previousScore;
    if (scoreDiff > maxScoreIncrease) {
      return false;
    }
  }
  
  const gameData = gameState.get(userId);
  if (gameData) {
    const timeSinceLastUpdate = Date.now() - gameData.lastUpdate;
    const maxPossibleScore = (timeSinceLastUpdate / 1000) * 100;
    
    if (newScore - (gameData.lastScore || 0) > maxPossibleScore) {
      return false;
    }
  }
  
  return true;
}

app.post('/api/register', loginLimiter, async (req, res) => {
  try {
    const { username, password } = req.body;
    
    if (!username || !password) {
      return res.status(400).json({ error: 'Username and password required' });
    }
    
    const sanitizedUsername = sanitizeInput(username);
    
    if (!validateUsername(sanitizedUsername)) {
      return res.status(400).json({ error: 'Invalid username format' });
    }
    
    if (typeof password !== 'string' || password.length < 8 || password.length > 128) {
      return res.status(400).json({ error: 'Password must be 8-128 characters' });
    }
    
    if (users.has(sanitizedUsername)) {
      return res.status(409).json({ error: 'Username already exists' });
    }
    
    const passwordHash = await hashPassword(password);
    const userId = generateSecureToken();
    
    users.set(sanitizedUsername, {
      userId,
      username: sanitizedUsername,
      passwordHash,
      createdAt: Date.now()
    });
    
    res.status(201).json({ message: 'User registered successfully' });
  } catch (error) {
    console.error('Registration error:', error.message);
    res.status(500).json({ error: 'Registration failed' });
  }
});

app.post('/api/login', loginLimiter, async (req, res) => {
  try {
    const { username, password } = req.body;
    
    if (!username || !password) {
      return res.status(400).json({ error: 'Username and password required' });
    }
    
    const sanitizedUsername = sanitizeInput(username);
    const user = users.get(sanitizedUsername);
    
    if (!user) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }
    
    const isValid = await verifyPassword(password, user.passwordHash);
    
    if (!isValid) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }
    
    const sessionToken = createSession(user.userId, user.username);
    
    res.json({ 
      sessionToken,
      username: user.username
    });
  } catch (error) {
    console.error('Login error:', error.message);
    res.status(500).json({ error: 'Login failed' });
  }
});

io.use((socket, next) => {
  const sessionToken = socket.handshake.auth.sessionToken;
  
  const session = validateSession(sessionToken);
  
  if (!session) {
    return next(new Error('Authentication failed'));
  }
  
  socket.userId = session.userId;
  socket.username = session.username;
  socket.sessionToken = sessionToken;
  
  next();
});

io.on('connection', (socket) => {
  console.log(`Player connected: ${socket.username}`);
  
  gameState.set(socket.userId, {
    lastUpdate: Date.now(),
    lastScore: 0,
    socketId: socket.id
  });
  
  socket.on('submitScore', (data) => {
    try {
      const session = validateSession(socket.sessionToken);
      
      if (!session || session.userId !== socket.userId) {
        socket.emit('error', { message: 'Session invalid' });
        socket.disconnect(true);
        return;
      }
      
      if (!data || typeof data !== 'object') {
        socket.emit('error', { message: 'Invalid data format' });
        return;
      }
      
      const { score } = data;
      
      if (!validateScore(score)) {
        socket.emit('error', { message: 'Invalid score value' });
        return;
      }
      
      const previousScore = playerScores.get(socket.userId) || 0;
      
      if (!verifyScoreIntegrity(socket.userId, score, previousScore)) {
        socket.emit('error', { message: 'Score validation failed' });
        console.warn(`Suspicious score from user ${socket.username}: ${score}`);
        return;
      }
      
      playerScores.set(socket.userId, score);
      
      const gameData = gameState.get(socket.userId);
      if (gameData) {
        gameData.lastScore = score;
        gameData.lastUpdate = Date.now();
      }
      
      socket.emit('scoreAccepted', { 
        score,
        username: socket.username
      });
      
      io.emit('leaderboardUpdate', getLeaderboard());
      
    } catch (error) {
      console.error('Score submission error:', error.message);
      socket.emit('error', { message: 'Score submission failed' });
    }
  });
  
  socket.on('getLeaderboard', () => {
    try {
      const session = validateSession(socket.sessionToken);
      
      if (!session) {
        socket.disconnect(true);
        return;
      }
      
      socket.emit('leaderboard', getLeaderboard());
    } catch (error) {
      console.error('Leaderboard error:', error.message);
    }
  });
  
  socket.on('disconnect', () => {
    console.log(`Player disconnected: ${socket.username}`);
    gameState.delete(socket.userId);
  });
});

function getLeaderboard() {
  const leaderboard = [];
  
  for (const [userId, score] of playerScores.entries()) {
    const user = Array.from(users.values()).find(u => u.userId === userId);
    if (user) {
      leaderboard.push({
        username: user.username,
        score: score
      });
    }
  }
  
  leaderboard.sort((a, b) => b.score - a.score);
  
  return leaderboard.slice(0, 10);
}

